: 8px;\n  }\n}\n/*=== MEDIA QUERY ===*/\n/* Ultra Mobile - Extra Small (320px - 400px) */\n@media (max-width: 400px) {\n  /* Typography */\n  h1, .h1 {\n    font-size: 28px;\n    line-height: 32px;\n  }\n  h2, .h2 {\n    font-size: 22px;\n    line-height: 28px;\n  }\n  h3, .h3 {\n    font-size: 18px;\n    line-height: 24px;\n  }\n  h4, .h4 {\n    font-size: 16px;\n    line-height: 22px;\n  }\n  body {\n    font-size: 14px;\n  }\n  /* Navbar */\n  .navbar-brand img {\n    height: 50px !important;\n  }\n  .dropdown-menu {\n    display: none;\n    width: 100%;\n    text-align: center;\n  }\n  .navbar-nav li {\n    padding: 0px;\n  }\n  .navbar-nav {\n    margin-top: 15px;\n  }\n  /* Sections & Containers */\n  .section {\n    padding: 40px 0;\n  }\n  .container {\n    padding-left: 12px;\n    padding-right: 12px;\n  }\n  /* Cards */\n  .card {\n    margin-bottom: 15px;\n  }\n  .card-body, .card > div[class*=p-] {\n    padding: 15px !important;\n  }\n  /* Buttons */\n  .btn {\n    padding: 12px 20px;\n    font-size: 12px;\n    height: auto;\n    min-height: 44px;\n  }\n  /* Forms */\n  input[type=email], input[type=password], input[type=text], input[type=tel] {\n    height: 44px;\n    font-size: 16px;\n  }\n  /* Text utilities */\n  .text-lg {\n    font-size: 18px;\n  }\n  .lead {\n    font-size: 14px;\n  }\n  .number {\n    font-size: 36px;\n    line-height: 45px;\n  }\n}\n/* Small Mobile (400px - 480px) */\n@media (max-width: 480px) {\n  /* Typography */\n  h1, .h1 {\n    font-size: 32px;\n    line-height: 36px;\n  }\n  h2, .h2 {\n    font-size: 26px;\n    line-height: 32px;\n  }\n  h3, .h3 {\n    font-size: 20px;\n    line-height: 26px;\n  }\n  h4, .h4 {\n    font-size: 17px;\n    line-height: 23px;\n  }\n  body {\n    font-size: 14px;\n  }\n  /* Navbar */\n  .navbar-brand img {\n    height: 60px !important;\n  }\n  .ml-lg-4 {\n    margin-left: 0 !important;\n  }\n  .navbar-collapse {\n    padding-top: 15px;\n  }\n  .dropdown-menu {\n    display: none;\n    text-align: center;\n  }\n  .navbar-nav li {\n    padding: 0px;\n  }\n  /* Hero Section */\n  .slider h1 {\n    font-size: 32px;\n    line-height: 38px;\n  }\n  .slider {\n    padding: 80px 15px !important;\n  }\n  /* Text utilities */\n  .text-lg {\n    font-size: 24px;\n    line-height: 32px;\n  }\n  .lead {\n    font-size: 14px;\n  }\n  .number {\n    font-size: 44px;\n    line-height: 55px;\n  }\n  /* Sections */\n  .section {\n    padding: 50px 0;\n  }\n  /* Cards */\n  .card {\n    margin-bottom: 20px;\n  }\n  /* Buttons */\n  .btn {\n    padding: 14px 25px;\n    font-size: 13px;\n    min-height: 44px;\n  }\n  /* Forms */\n  input[type=email], input[type=password], input[type=text], input[type=tel] {\n    height: 44px;\n  }\n  /* Media elements */\n  .media {\n    display: block;\n  }\n  .media-body {\n    margin-top: 20px;\n  }\n}\n/* Tablet (480px - 768px) */\n@media (max-width: 768px) {\n  /* Typography */\n  h1, .h1 {\n    font-size: 36px;\n    line-height: 42px;\n  }\n  h2, .h2 {\n    font-size: 28px;\n    line-height: 34px;\n  }\n  h3, .h3 {\n    font-size: 22px;\n    line-height: 28px;\n  }\n  h4, .h4 {\n    font-size: 18px;\n    line-height: 24px;\n  }\n  body {\n    font-size: 15px;\n  }\n  /* Navbar */\n  .ml-lg-4 {\n    margin-left: 0 !important;\n  }\n  /* Sections */\n  .section {\n    padding: 60px 15px;\n  }\n  .container {\n    padding-left: 15px;\n    padding-right: 15px;\n  }\n  /* Cards - better spacing */\n  .card {\n    margin-bottom: 25px;\n  }\n  /* Media elements */\n  .media {\n    display: block;\n  }\n  .media-body {\n    margin-top: 20px;\n  }\n  .services .media img {\n    width: 100% !important;\n  }\n  .dropdown-menu {\n    display: none;\n    text-align: center;\n  }\n  .navbar-nav li {\n    padding: 0px;\n  }\n  /* Column overrides for better tablet layout */\n  .col-sm-6 {\n    flex: 0 0 50%;\n    max-width: 50%;\n  }\n}\n/* Desktop (768px - 992px) */\n@media (max-width: 992px) {\n  /* Better spacing on desktop */\n  .section {\n    padding: 80px 0;\n  }\n}\n/* Large Desktop (992px - 1200px) */\n@media (max-width: 1200px) {\n  .section {\n    padding: 80px 0;\n  }\n}","html,body{\n  overflow-x: hidden;\n  width: 100%;\n  word-wrap: break-word;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n* {\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n.navbar-toggle .icon-bar {\n  background: $primary-color;\n}\n\ninput[type=\"email\"],input[type=\"password\"],input[type=\"text\"],input[type=\"tel\"]{\n  box-shadow:none;\n  height:50px;\n  outline: none;\n  font-size:14px;\n  &:focus {\n    box-shadow: none;\n    border:1px solid $primary-color;\n  }\n}\n\n\n.form-control {\n  box-shadow: none;\n  border-radius: 0;\n  &:focus {\n    box-shadow:none;\n    border:1px solid $primary-color;\n  }\n}\n\n\n// Button Style\n\n.btn {\n  display: inline-block;\n  font-size: 14px;\n  letter-spacing: 1px;\n  padding: 18px 35px;\n  text-transform: uppercase;\n  border-radius:0;\n  font-weight: 700;\n  @include transition (all, 0.5s, ease);\n  border:1px solid transparent;\n}\n\n\n.btn-main{\n  background:  linear-gradient(90deg, #a31919 0%, #b74c4c 100%);\n  color: $light;\n  &:hover{\n    background:  linear-gradient(90deg,  #b74c4c 0%,#a31919  100%);\n    color: $light!important;\n     -webkit-transform: translateY(-5px);\n        -moz-transform: translateY(-5px);\n         -ms-transform: translateY(-5px);\n          -o-transform: translateY(-5px);\n             transform: translateY(-5px);\n  }\n}\n.btn-solid-border {\n  border:2px solid $primary-color;\n  background:transparent;\n  color:$light;\n  &:hover {\n    border:2px solid $primary-color;\n    background:$primary-color;\n  }\n}\n.btn-white {\n  border:2px solid $light;\n  background:$light;\n  color:$black;\n  &:hover {\n    border:1px solid $primary-color;\n    background:$primary-color;\n    color:$light!important;\n  }\n}\n\n\n.btn-transparent {\n  @extend .btn-main;\n  background:transparent;\n  padding:0;\n  color:$primary-color;\n  &:hover {\n    background:transparent;\n    color:$primary-color;\n  }\n}\n\n.btn-large {\n  padding:20px 45px;\n  &.btn-icon {\n    i {\n      font-size:16px;\n      vertical-align:middle;\n      margin-right:5px;\n    }\n  }\n}\n.btn-small {\n  @extend .btn-main ;\n  padding:10px 25px;\n  font-size:12px;\n}\n\n.btn-round {\n  border-radius:4px;\n}\n.btn-round-full {\n  border-radius:50px;\n}\n\n\n.btn.active:focus, .btn:active:focus, .btn:focus {\n  outline: 0;\n}\n\n\n\n\n\n\n.bg-shadow {\n  background-color: $light;\n  box-shadow: 0 16px 24px rgba(0,0,0,.08);\n  padding:20px;\n}\n\n.bg-gray {\n  background:#f0f2f4;\n}\n.bg-primary {\n  background:$primary-color!important;\n}\n\n.section {\n  padding:100px 0;\n  background: #fff;\n}\n\n\n.section-title {\n  margin-bottom: 70px;\n \n .title{\n  font-size: 50px;\n  line-height: 50px;\n }\n  \n  h2 {\n    color: #232323 !important;\n    font-weight: 700 !important;\n  }\n\n  p {\n    color: #666 !important;\n    font-family: $secondary-font;\n  }\n}\n\n\n\n.page-title{\n  padding: 155px 0 100px;\n  background: url(\"../images/bg/bg-72.jpg\") no-repeat center center;\n  background-size: cover;\n  background-attachment: fixed;\n  min-height: 400px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n\n  &:before {\n    content: \"\";\n    position: absolute;\n    left: 0;\n    top: 0;\n    bottom: 0;\n    right: 0;\n    width: 100%;\n    height: 100%;\n    background: rgba(0,0,0,.6);\n    z-index: 1;\n  }\n\n  h1 {\n    position: relative;\n    z-index: 2;\n    color: #fff;\n  }\n}\n\n/* Responsive Page Title */\n@media (max-width: 992px) {\n  .page-title {\n    padding: 120px 20px;\n    min-height: 350px;\n  }\n\n  .page-title h1 {\n    font-size: 42px;\n  }\n}\n\n@media (max-width: 768px) {\n  .page-title {\n    padding: 100px 15px;\n    min-height: 320px;\n    background-attachment: scroll;\n  }\n\n  .page-title h1 {\n    font-size: 32px;\n    line-height: 40px;\n  }\n}\n\n@media (max-width: 480px) {\n  .page-title {\n    padding: 80px 12px;\n    min-height: 280px;\n    background-position: center 30%;\n  }\n\n  .page-title h1 {\n    font-size: 24px;\n    line-height: 32px;\n  }\n}\n\n\n.overly {\n  position: relative;\n  &:before{\n    content: \"\";\n    position: absolute;\n    left: 0;\n    top: 0;\n    bottom: 0;\n    right: 0;\n    width: 100%;\n    height: 100%;\n    background: #232323;\n    opacity: 0.8;\n  }\n}\n\n\n\n.overly-2{\n  position: relative;\n  &:before{\n    content: \"\";\n    position: absolute;\n    left: 0;\n    top: 0;\n    bottom: 0;\n    right: 0;\n    width: 100%;\n    height: 100%;\n    background:#000;\n    opacity: 0.6;\n  }\n}\n\n\n\n#success , #error {\n    display: none;\n}\n\n\n.text-color{\n  color: $primary-color;\n}\n\n.text-black{\n  color: $black;\n}\n\n.text-sm{\n  font-size: 14px;\n}\n.text-md{\n  font-size: 26px;\n  line-height: 36px;\n}\n.text-lg{\n  font-size: 56px;\n  line-height: 66px;\n}\n\n.no-spacing{\n  letter-spacing: 0px\n}\n\n\na{\n  -webkit-transition: all .35s ease;\n       -moz-transition: all .35s ease;\n        -ms-transition: all .35s ease;\n         -o-transition: all .35s ease;\n            transition: all .35s ease;\n}\na:hover,a:focus{\n  color: $primary-color!important;\n  text-decoration: none!important;\n  outline:0;\n}\n\n\n.font-size-13{\n  font-size: 13px;\n}\n\n.letter-spacing{\n  letter-spacing: 1px;\n}\n\n\n\n.bg-black-50{\n  background: $extra-color;\n}\n\n/* Responsive image handling */\nimg {\n  max-width: 100%;\n  height: auto;\n  display: block;\n}\n\nimg.img-fluid {\n  max-width: 100%;\n  width: 100%;\n  height: auto;\n}\n\n/* Container & row responsive */\n.container, .container-fluid {\n  width: 100%;\n  padding-left: 15px;\n  padding-right: 15px;\n  margin-left: auto;\n  margin-right: auto;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n.row {\n  margin-left: -15px;\n  margin-right: -15px;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n[class*=\"col-\"] {\n  padding-left: 15px;\n  padding-right: 15px;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n/* Text overflow prevention */\nh1, h2, h3, h4, h5, h6 {\n  word-wrap: break-word;\n  overflow-wrap: break-word;\n  -webkit-hyphens: auto;\n  -moz-hyphens: auto;\n  hyphens: auto;\n}\n\np, span, a, li {\n  word-wrap: break-word;\n  overflow-wrap: break-word;\n}\n\n/* Card responsive */\n.card {\n  width: 100%;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n/* Mobile-first responsive utilities */\n@media (max-width: 992px) {\n  .ml-lg-4 {\n    margin-left: 0 !important;\n  }\n  .mt-lg-0 {\n    margin-top: 0 !important;\n  }\n  .ml-auto {\n    margin-left: auto;\n  }\n}","// Transition\n@mixin transition($what: all, $time: 0.2s, $how: ease-in-out) {\n    -webkit-transition: $what $time $how;\n    -moz-transition:    $what $time $how;\n    -ms-transition:     $what $time $how;\n    -o-transition:      $what $time $how;\n    transition:         $what $time $how;\n}\n\n// Transform\n@mixin transform($transforms) {\n\t   -moz-transform: $transforms;\n\t     -o-transform: $transforms;\n\t    -ms-transform: $transforms;\n\t-webkit-transform: $transforms;\n          transform: $transforms;\n}\n// rotate\n@mixin rotate ($deg) {\n  @include transform(rotate(#{$deg}deg));\n}\n \n// scale\n@mixin scale($scale) {\n\t @include transform(scale($scale));\n} \n// translate\n@mixin translate ($x, $y) {\n   @include transform(translate($x, $y));\n}\n// skew\n@mixin skew ($x, $y) {\n   @include transform(skew(#{$x}deg, #{$y}deg));\n}\n//transform origin\n@mixin transform-origin ($origin) {\n    moz-transform-origin: $origin;\n\t     -o-transform-origin: $origin;\n\t    -ms-transform-origin: $origin;\n\t-webkit-transform-origin: $origin;\n          transform-origin: $origin;\n}",".navbar-nav{\n\n  li{\n    padding: 0px 10px;\n  }\n .nav-link{\n    font-family: $secondary-font;\n    color: $light;\n    text-transform: uppercase;\n    font-size: 17px;\n    letter-spacing: 1px;\n\n    -webkit-transition: all .25s ease;\n       -moz-transition: all .25s ease;\n        -ms-transition: all .25s ease;\n         -o-transition: all .25s ease;\n            transition: all .25s ease;\n    \n    &:hover, &:focus{\n      color: $primary-color;\n    }\n  }\n\n\n}\n\n\n\n.top-header{\n  border-bottom: 1px solid rgba(0,0,0,0.05);\n  font-size: 14px;\n  ul li{\n    padding: 0px 25px;\n    border-left: 1px solid $border-color;\n  }\n}\n\n.dropdown{\n  height: 100%;\n}\n.dropdown-menu {\n    background: #1c1c1c;\n    border-radius: 0px;\n    box-shadow: 0 5px 5px 0 rgba(0,0,0,.03);\n    padding: 24px 0 26px;\n    min-width: 280px;\n    left:0px;\n    top: 100%;\n    -webkit-transform: translateY(10%);\n       -moz-transform: translateY(10%);\n        -ms-transform: translateY(10%);\n         -o-transform: translateY(10%);\n            transform: translateY(10%);\n    visibility: hidden;\n    opacity: 0;\n    z-index: 10;\n    transition:all .3s ease 0s;\n    display: block;\n}\n\n.dropdown-item {\n    color: #c8c8c8;\n    text-transform: uppercase;\n    letter-spacing: 1px;\n    font-size: 12px;\n    padding: .55rem 2rem;\n}\n\n.dropdown-toggle::after {\n    display: none;\n}\n\n.dropdown:hover .dropdown-menu{\n    visibility: visible;\n    opacity: 1;\n    z-index: 20;\n      -webkit-transform: translateY(0%);\n       -moz-transform: translateY(0%);\n        -ms-transform: translateY(0%);\n         -o-transform: translateY(0%);\n            transform: translateY(0%);\n  }\n\n.dropdown-item:hover{\n  background:transparent;\n  color: $primary-color;\n}\n\nul.dropdown-menu li {\n    padding-left: 0px!important;\n}\n\n\n\n.fixed-nav{\n  background: $extra-color;\n}\n\n.navbar-toggler {\n    background-color:$light;\n    border: 1px solid $light;\n    border-radius: 0px;\n    padding: 5px 10px;\n}\n\n.navbar-collapse.collapse.show{\n  background: $extra-color;\n}\n\n/* Responsive Navbar */\n@media (max-width: 992px) {\n  .navbar-nav li {\n    padding: 0px;\n  }\n  \n  .nav-link {\n    font-size: 14px;\n    padding: 12px 0;\n  }\n  \n  .dropdown-menu {\n    min-width: auto;\n    background: #232323;\n  }\n}\n\n@media (max-width: 768px) {\n  .navbar-nav li {\n    padding: 8px 0;\n  }\n  \n  .nav-link {\n    font-size: 13px;\n    letter-spacing: 0.5px;\n    padding: 10px 0;\n  }\n  \n  .dropdown-menu {\n    padding: 15px 0 20px;\n    min-width: 100%;\n  }\n  \n  .dropdown-item {\n    padding: 0.4rem 1rem;\n    font-size: 11px;\n  }\n}\n\n@media (max-width: 480px) {\n  .navbar-nav li {\n    padding: 5px 0;\n  }\n  \n  .nav-link {\n    font-size: 12px;\n    letter-spacing: 0px;\n    padding: 8px 0;\n  }\n\n  .navbar-brand img {\n    height: 60px !important;\n  }\n\n  .text-lg-right {\n    text-align: center !important;\n  }\n}",".slider{\n\tbackground: url(\"../images/bg/bg-71.jpg\") no-repeat center center;\n\tbackground-size: cover;\n\tbackground-attachment: fixed;\n\tpadding: 200px 0px;\n\tmin-height: 600px;\n\tdisplay: flex;\n\talign-items: center;\n\tjustify-content: center;\n\twidth: 100%;\n\toverflow: hidden;\n\n\t@extend .overly-2;\n\n\th1{\n\t\tfont-size: 85px;\n\t\tline-height: 110px;\n\t}\n\n\tspan.subhead{\n\t\tcolor:$light;\n\t\tletter-spacing: 5px;\n\t\tborder: 2px solid $light;\n\t\tpadding: 3px 15px 5px 15px;\n\t\topacity: .8;\n\t}\n}\n\n/* Responsive Slider */\n@media (max-width: 1200px) {\n\t.slider {\n\t\tmin-height: 550px;\n\t}\n}\n\n@media (max-width: 992px) {\n\t.slider {\n\t\tpadding: 150px 20px;\n\t\tmin-height: 500px;\n\t\tbackground-attachment: fixed;\n\t}\n\n\t.slider h1 {\n\t\tfont-size: 56px;\n\t\tline-height: 70px;\n\t}\n\n\t.slider span.subhead {\n\t\tletter-spacing: 2px;\n\t\tpadding: 3px 12px 5px 12px;\n\t\tfont-size: 1