margin-bottom: 20px;\n  }\n  \n  /* Buttons */\n  .btn {\n    padding: 14px 25px;\n    font-size: 13px;\n    min-height: 44px;\n  }\n\n  /* Forms */\n  input[type=email], input[type=password], input[type=text], input[type=tel] {\n    height: 44px;\n  }\n\n  /* Media elements */\n  .media{\n    display: block;\n  }\n  .media-body{\n    margin-top: 20px;\n  }\n}\n\n/* Tablet (480px - 768px) */\n@include tablet{\n  /* Typography */\n  h1, .h1 {\n    font-size: 36px;\n    line-height: 42px;\n  }\n  h2, .h2 {\n    font-size: 28px;\n    line-height: 34px;\n  }\n  h3, .h3 {\n    font-size: 22px;\n    line-height: 28px;\n  }\n  h4, .h4 {\n    font-size: 18px;\n    line-height: 24px;\n  }\n  body {\n    font-size: 15px;\n  }\n\n  /* Navbar */\n  .ml-lg-4 {\n    margin-left: 0 !important;\n  }\n\n  /* Sections */\n  .section {\n    padding: 60px 15px;\n  }\n  .container {\n    padding-left: 15px;\n    padding-right: 15px;\n  }\n\n  /* Cards - better spacing */\n  .card {\n    margin-bottom: 25px;\n  }\n\n  /* Media elements */\n  .media{\n    display: block;\n  }\n  .media-body{\n    margin-top: 20px;\n  }\n  .services .media img{\n    width: 100%!important;\n  }\n  \n  .dropdown-menu {\n    display: none;\n    text-align: center;\n  }\n  .navbar-nav li{\n    padding: 0px;\n  }\n\n  /* Column overrides for better tablet layout */\n  .col-sm-6 {\n    flex: 0 0 50%;\n    max-width: 50%;\n  }\n}\n\n/* Desktop (768px - 992px) */\n@include desktop{\n  .navbar-nav .dropdown-menu{\n    // display: block;\n  }\n  \n  /* Better spacing on desktop */\n  .section {\n    padding: 80px 0;\n  }\n}\n\n/* Large Desktop (992px - 1200px) */\n@include large-desktop{\n   .navbar-nav .dropdown-menu{\n    // display: block;\n  }\n   \n  .section {\n    padding: 80px 0;\n  }\n}"]}